pub fn process_swap(
    program_id: &Pubkey,
    amount_in: u64,
    accounts: &[AccountInfo],
) -> ProgramResult {
    let token_swap = SwapVersion::unpack(&swap_info.data.borrow())?;

    let result = token_swap
        .swap_curve()
        .swap(
            amount_in as u128,
            source_account.amount as u128,
            dest_account.amount as u128,
            trade_direction,
            token_swap.fees(),
        )
        .unwrap();

    let amount_out = result.destination_amount_swapped as u64;

    Self::token_transfer(swap_info.key, source_token_program_info.clone(),
        source_info.clone(), source_token_mint_info.clone(),
        swap_source_info.clone(), user_transfer_authority_info.clone(),
        token_swap.bump_seed(), amount_in, source_mint_decimals)?;

    Self::token_transfer(swap_info.key, destination_token_program_info.clone(),
        swap_destination_info.clone(), destination_token_mint_info.clone(),
        destination_info.clone(), authority_info.clone(),
        token_swap.bump_seed(), amount_out, destination_mint_decimals)?;

    Ok(())
}

